unsigned int binomial(unsigned int n, unsigned int k) {
    if (k > n) return 0;
    if (k == 0 || k == n) return 1;
    if (k > n - k) k = n - k;
    unsigned int result = 1;
    for (unsigned int i = 0; i < k; i++) {
        result = result * (n - i) / (i + 1);
    }
    return result;
}

