def integer_sqrt(n: int) -> int:
    if n == 0:
        return 0
    x = n
    y = (x + 1) // 2
    while y < x:
        x = y
        y = (x + n // x) // 2
    return x

def is_perfect_square(n: int) -> bool:
    s = integer_sqrt(n)
    return s * s == n

